DELIMITER $$
CREATE TRIGGER `log_edit_stok_barang` AFTER UPDATE ON `master_barang` FOR EACH ROW BEGIN
    -- Jika stok_akhir berubah, catat rincian stoknya
    IF OLD.stok_akhir <> NEW.stok_akhir THEN
        VALUES (
            @user_aksi, 
            'UPDATE STOK', 
            CONCAT('Update stok ', NEW.nama_barang, ': ', OLD.stok_akhir, ' -> ', NEW.stok_akhir), 
            '127.0.0.1', 
            NOW()
        );
    -- Jika yang berubah bukan stok (misal nama atau lokasi), catat update umum
    ELSE
        VALUES (
            @user_aksi, 
            'UPDATE', 
            CONCAT('Mengubah info barang: ', NEW.nama_barang), 
            '127.0.0.1', 
            NOW()
        );
    END IF;
END
$$
DELIMITER ;
DELIMITER $$
CREATE TRIGGER `log_hapus_barang` AFTER DELETE ON `master_barang` FOR EACH ROW BEGIN
    VALUES (@user_aksi, 'HAPUS BARANG', CONCAT('MENGHAPUS: ', OLD.nama_barang, ' | Stok Terakhir: ', OLD.stok_akhir), 'Trigger');
END
$$
DELIMITER ;
